.darma-loader-darma-custom-505 {color: var(--loader-color, #0284c7);
   width: 40px;
   aspect-ratio: 1;
   position: relative;
}
.darma-loader-darma-custom-505:before, .darma-loader-darma-custom-505:after  {
  content: "";
   position: absolute;
   top: 0;
   left: 0;
   margin: -8px 0 0 -8px;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #0284c7);
   animation: darma-loader-darma-custom-505-l1-1 2s infinite, darma-loader-darma-custom-505-l1-2 .5s infinite;
}
.darma-loader-darma-custom-505:after  {
  background:var(--loader-secondary-color, #7dd3fc);
   animation-delay: -1s,0s;
}
@keyframes darma-loader-darma-custom-505-l1-1  {
  0% {top:0 ;
  left:0}
25% {top:100%;
  left:0}
50% {top:100%;
  left:100%}
75% {top:0 ;
  left:100%}
100% {top:0 ;
  left:0}
}
@keyframes darma-loader-darma-custom-505-l1-2  {
  80%,100% {transform: rotate(0.5turn)}
}

